package com.chaobo.scm.supplier.application.order;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.integration.InboundEventPayloadStore;import com.chaobo.scm.supplier.application.masterdata.MasterDataEventConsumeLogPort;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.order.PoConfirmAggregate;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.Set;
@Service public class PurchaseOrderEventConsumerApplicationService{public static final String CONSUMER="supplier-purchase-order";private final MasterDataEventConsumeLogPort inbox;private final InboundEventPayloadStore payloads;private final PoConfirmApplicationService orders;public PurchaseOrderEventConsumerApplicationService(MasterDataEventConsumeLogPort inbox,InboundEventPayloadStore payloads,PoConfirmApplicationService orders){this.inbox=inbox;this.payloads=payloads;this.orders=orders;}@Transactional public CommandResult consume(PurchaseOrderEvent event){var claim=inbox.claim("PURCHASE",event.eventCode(),event.eventType(),CONSUMER,"PURCHASE:"+event.eventCode());if(claim==MasterDataEventConsumeLogPort.ClaimResult.ALREADY_SUCCEEDED)return current(event);if(claim==MasterDataEventConsumeLogPort.ClaimResult.IN_PROGRESS)throw new BusinessException(ErrorCode.IDEMPOTENCY_CONFLICT,"采购订单事件正在处理");payloads.save("PURCHASE",event.eventCode(),CONSUMER,event);try{var context=new CommandContext(0,"PURCHASE",0,null,event.eventCode(),null,"PURCHASE:"+event.eventCode(),Set.of("supplier:openapi:purchase_order:receive"));CommandResult result=switch(event.eventType()){case "PurchaseOrderReleased","PurchaseOrderChanged"->orders.receive(event.purchaseOrderId(),event.purchaseOrderNo(),event.supplierId(),event.confirmDeadline(),event.lines().stream().map(line->new PoConfirmAggregate.NewLine(line.skuCode(),line.orderQuantity(),line.requestedDeliveryDate())).toList(),event.sourceVersion(),context);case "PurchaseOrderCancelled"->orders.cancelByPurchase(event.purchaseOrderId(),event.sourceVersion(),event.reason(),context);case "PurchaseOrderClosed"->orders.closeByPurchase(event.purchaseOrderId(),event.sourceVersion(),context);default->throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"不支持的采购订单事件: "+event.eventType());};inbox.markSucceeded("PURCHASE",event.eventCode(),CONSUMER,false);return result;}catch(RuntimeException exception){inbox.recordFailure("PURCHASE",event.eventCode(),event.eventType(),CONSUMER,"PURCHASE:"+event.eventCode(),exception.getMessage());throw exception;}}private CommandResult current(PurchaseOrderEvent event){return orders.detailByPurchaseOrder(event.purchaseOrderId());}}
